class MijnAfvalwijzerCard extends HTMLElement {
  setConfig(config) {
    if (!config.entity) {
      throw new Error("Please define an entity");
    }
    this.config = config;
    this.attachShadow({ mode: "open" });
  }

  set hass(hass) {
    this._hass = hass;
    this.render();
  }

  getCardSize() {
    return 2;
  }

  render() {
    if (!this._hass || !this.config || !this.shadowRoot) return;

    const entity = this._hass.states[this.config.entity];
    if (!entity) {
      this.shadowRoot.innerHTML = `<ha-card><div style="padding:16px;">Entity not found: ${this.config.entity}</div></ha-card>`;
      return;
    }

    const attrs = entity.attributes;
    const wasteType = attrs.type || "";
    const wasteTypeFull = attrs.type_full || wasteType;
    const daysUntil = attrs.days_until;
    const nextType = attrs.next_type || "";
    const nextTypeFull = attrs.next_type_full || nextType;
    const nextDate = attrs.next_date || "";
    const nextDays = attrs.next_days_until;

    const iconUrls = {
      "PMD": "data:image/png;base64,",
      "GFT": "data:image/png;base64,",
      "Restafval": "data:image/png;base64,",
      "Papier": "data:image/png;base64,",
    };

    const colors = {
      "GFT": "#4CAF50",
      "PMD": "#FF9800",
      "Restafval": "#9E9E9E",
      "Papier": "#2196F3",
    };

    const iconUrl = iconUrls[wasteType] || iconUrls["Restafval"];
    const color = colors[wasteType] || "#8b8b8b";
    const nextIconUrl = iconUrls[nextType] || iconUrls["Restafval"];
    const nextColor = colors[nextType] || "#8b8b8b";

    let status, statusColor;
    if (daysUntil === 0) {
      status = "Vandaag";
      statusColor = "#F44336";
    } else if (daysUntil === 1) {
      status = "Morgen";
      statusColor = "#FF9800";
    } else if (daysUntil <= 3) {
      status = `Over ${daysUntil} dagen`;
      statusColor = "#FF9800";
    } else {
      status = `Over ${daysUntil} dagen`;
      statusColor = "#8b8b8b";
    }

    const mainDate = entity.state !== "unavailable" && entity.state !== "unknown"
      ? new Date(entity.state + "T00:00:00").toLocaleDateString("nl-NL", {
          weekday: "long", day: "numeric", month: "long"
        })
      : "Geen data";

    let nextDateFormatted = "";
    if (nextDate) {
      nextDateFormatted = new Date(nextDate + "T00:00:00").toLocaleDateString("nl-NL", {
        weekday: "short", day: "numeric", month: "short"
      });
    }

    this.shadowRoot.innerHTML = `
      <style>
        :host {
          display: block;
        }
        ha-card {
          padding: 0;
        }
        .card-content {
          padding: 16px;
        }
        .header {
          display: flex;
          align-items: center;
          gap: 12px;
        }
        .waste-icon {
          width: 44px;
          height: 44px;
          border-radius: 10px;
          object-fit: cover;
          flex-shrink: 0;
        }
        .waste-icon-small {
          width: 16px;
          height: 16px;
          object-fit: contain;
          flex-shrink: 0;
        }
        .info {
          flex: 1;
          min-width: 0;
        }
        .type {
          font-size: 14px;
          font-weight: 600;
          color: var(--primary-text-color);
        }
        .date {
          font-size: 13px;
          color: var(--secondary-text-color);
          margin-top: 1px;
        }
        .badge {
          font-size: 12px;
          font-weight: 600;
          padding: 4px 10px;
          border-radius: 20px;
          white-space: nowrap;
          flex-shrink: 0;
        }
        .next {
          display: flex;
          align-items: center;
          gap: 6px;
          margin-top: 10px;
          padding-top: 10px;
          border-top: 1px solid var(--divider-color);
          font-size: 12px;
          color: var(--secondary-text-color);
        }
        .next-days {
          color: var(--disabled-text-color);
        }
      </style>
      <ha-card>
        <div class="card-content">
          <div class="header">
            <img src="${iconUrl}" class="waste-icon" />
            <div class="info">
              <div class="type">${wasteTypeFull}</div>
              <div class="date">${mainDate}</div>
            </div>
            <div class="badge" style="background: ${statusColor}22; color: ${statusColor};">${status}</div>
          </div>
          ${nextType ? `
          <div class="next">
            <img src="${nextIconUrl}" class="waste-icon-small" />
            <span>${nextTypeFull} — ${nextDateFormatted}</span>
            <span class="next-days">(${nextDays}d)</span>
          </div>
          ` : ""}
        </div>
      </ha-card>
    `;
  }
}

customElements.define("mijnafvalwijzer-card", MijnAfvalwijzerCard);

window.customCards = window.customCards || [];
window.customCards.push({
  type: "mijnafvalwijzer-card",
  name: "Mijn Afvalwijzer",
  description: "Toont de eerstvolgende afvalophaling",
});
